import os, base64, gzip
base = os.path.dirname(os.path.abspath(__file__))
FILES = [
  ('src\\\\app\\\\api\\\\site-config\\\\route.ts', ''),
  ('src\\\\components\\\\layout\\\\Footer.tsx', ''),
  ('src\\\\components\\\\layout\\\\WhatsAppFloat.tsx', ''),
  ('src\\\\app\\\\layout.tsx', ''),
  ('src\\\\app\\\\checkout\\\\page.tsx', ''),
]
ok = 0
for rel, data in FILES:
    try:
        dest = os.path.join(base, rel)
        os.makedirs(os.path.dirname(dest), exist_ok=True)
        with open(dest, "w", encoding="utf-8", newline="\n") as f:
            f.write(gzip.decompress(base64.b64decode(data)).decode("utf-8"))
        print("OK:", rel)
        ok += 1
    except Exception as e:
        print("ERRO:", rel, e)
print()
print(f"Total: {ok}/5 arquivos corrigidos")
print()
print("Footer e WhatsApp agora buscam config em tempo real (sem cache)")
print("Rode: npm run build")